A题 切蛋糕题目链接 ：https://ac.nowcoder.com/acm/contest/11746/A基本思路是将1/k进行二进制拆分，比如说对于k=5，1 / 5 的二进制为 0.001100110011，则应存在5份大小为0.001的蛋糕，5份大小为0.0001的蛋糕，以此类推。（看到2的几次方相加就应该想到二进制拆分）代码不会写Orz，还不会实现，先留着之后补。
B题 小宝的幸运数组题目链接 ：https://ac.nowcoder.com/acm/contest/11746/B题目的思路大概是一个同余的相互跳的一个搜索之类的东西，很巧妙。
#include&lt;bits&#x2F;stdc++.h&gt;
using namespace std;
const int maxn &#x3D; 1e5 + 10;
typedef long long ll;
ll T, n, k, ans, sum, t;
ll head[maxn];
int main() &#123;
	for (scanf(&quot;%ld&quot;, &amp;T);T;T--) &#123;&#x2F;&#x2F;学来的多组处理
		scanf(&quot;%ld%ld&quot;, &amp;n, &amp;k);
		ans &#x3D; sum &#x3D; 0;
		for (int i&#x3D;0;i&lt;&#x3D;k;++i)	head[i] &#x3D; -1;&#x2F;&#x2F;head[x]表示的是第一次出现总和加到一起的余数为x的时候的a的位置是多少。这样可以一边加一边处理，如果某个数加到总和上之后和之前第一次的余数对应上了，说明这之间的数字的和可以被K整除。
		head[0] &#x3D; 0;&#x2F;&#x2F;显然对于余数为0来说，不需要有数字加上就行。
		for (int i&#x3D;1;i&lt;&#x3D;n;++i) &#123;
			scanf(&quot;%ld&quot;, &amp;t);
			sum &#x3D; (sum + t) % k;&#x2F;&#x2F;维持一个加上当前值然后在k里的一个特征值。
			if (head[sum] !&#x3D; -1) 
				ans &#x3D; max(ans, i - head[sum]);&#x2F;&#x2F;维护答案 
			else 
				head[sum] &#x3D; i;&#x2F;&#x2F;如果第一次出现的话就保存位置
		&#125;
		ans &#x3D; ans &#x3D;&#x3D; 0 ? -1 : ans;
		printf(&quot;%ld\n&quot;, ans);
	&#125;
	return 0;
&#125;
C题 上进的凡凡这道题的思路是：一个非降序数组的所有子串都为非降序，只要把给定数组分为若干个非降序部分（每个部分要尽可能长），然后计算子串数，对于长度为n的数组子串数为 n * (n + 1) / 2，遍历然后相加。思路的正确性：一个非降序数组的所有子串都为非降序串。
#include&lt;bits&#x2F;stdc++.h&gt;
using namespace std;

const int maxn &#x3D; 100005;
typedef long long ll;

ll a[maxn];
ll sum, n;
int main() &#123;
	ios :: sync_with_stdio(false);
	cin &gt;&gt; n;
	for (int i &#x3D; 1; i &lt;&#x3D; n; i++)	cin &gt;&gt; a[i];
	for (ll i &#x3D; 1,t &#x3D; 1; i &lt;&#x3D; n; ) &#123;
		t &#x3D; i;
		t++;
		while (a[t] &gt;&#x3D; a[t - 1] &amp;&amp; t &lt;&#x3D; n)
			t++;
		ll ans &#x3D; t - i;
		sum +&#x3D; ans * (ans + 1)&#x2F;2;
		i &#x3D; t;
	&#125;
	cout &lt;&lt; sum &lt;&lt; endl;
	return 0;
&#125;
